    96→**`src/lib/stores/status-store.ts`**
    97→```typescript
    98→import { atom } from 'nanostores';
    99→import type { ConnectionStatus } from '../types';
   100→
   101→export const statusStore = atom<ConnectionStatus>('connecting');
   102→```
   103→
   104→**`src/lib/stores/market-store.ts`**
   105→```typescript
   106→import { atom } from 'nanostores';
   107→import type { MarketData } from '../types';
   108→
   109→export const marketStore = atom<MarketData | null>(null);
